```python
class Solution:
    def equalDistanceBinary(self, n: int) -> int:
        positions = []
        pos = 0

        # 从低位到高位遍历二进制位
        while n > 0:
            if n & 1:
                positions.append(pos)  # 记录当前 1 的位置
            n >>= 1
            pos += 1

        # 不少于 3 个 1
        if len(positions) < 3:
            return -1

        # 计算标准距离：相邻 1 的位置差 - 1
        distance = positions[1] - positions[0] - 1

        # 检查所有相邻 1 之间的距离是否相同
        for i in range(2, len(positions)):
            cur_distance = positions[i] - positions[i - 1] - 1
            if cur_distance != distance:
                return -1

        return distance
```

```java
class Solution {
    public int equalDistanceBinary(int n) {
        int[] positions = new int[31];
        int count = 0;
        int pos = 0;

        // 从低位到高位遍历二进制位
        while (n > 0) {
            if ((n & 1) == 1) {
                positions[count++] = pos; // 记录当前 1 的位置
            }
            n >>= 1;
            pos++;
        }

        // 不少于 3 个 1
        if (count < 3) {
            return -1;
        }

        // 计算标准距离：相邻 1 的位置差 - 1
        int distance = positions[1] - positions[0] - 1;

        // 检查所有相邻 1 之间的距离是否相同
        for (int i = 2; i < count; i++) {
            int curDistance = positions[i] - positions[i - 1] - 1;
            if (curDistance != distance) {
                return -1;
            }
        }

        return distance;
    }
}
