int equalDistanceBinary(int n) {
    // 记录所有 1 的位置
    int positions[31];
    int count = 0;
    int pos = 0;
    while (n > 0) {
        if (n & 1) {
            positions[count++] = pos; // 记录当前 1 的位置
        }
        n >>= 1;
        pos++;
    }

    // 至少需要 3 个 1
    if (count < 3) return -1;

