    int distance = positions[1] - positions[0] - 1;

    // 检查所有相邻 1 之间的距离是否一致
    for (int i = 2; i < count; i++) {
        int curDist = positions[i] - positions[i - 1] - 1;
        if (curDist != distance) return -1;
    }
    return distance;
}
